examples.toCode:
use std::num::ParseIntError;

fn parse_positive(s: &str) -> Result<u32, String> {
    let n: i64 = s.parse().map_err(|e: ParseIntError| e.to_string())?;
    if n <= 0 {
        return Err(format!("Expected positive, got {}", n));
    }
    Ok(n as u32)
}

